    fn test_coherence_percents() {
        // Create a CharsetMatch instance with coherence values
        let charset_match = CharsetMatch::new(
            &b"Test"[..],
            "utf-8",
            0.01,
            false,
            &vec![
                CoherenceMatch {
                    language: &Language::Russian,
                    score: 0.5, // coherence of 0.5
                },
            ],
            None,
        );

        // Test basic coherence conversion
        let result = charset_match.coherence_percents();
        assert!((result - 50.0).abs() < 0.0001, "Expected 50.0, got {}", result); // Expected 0.5 * 100.0 = 50.0

        // Testing various coherence values
        let coherence_test_cases = [
            (0.0, 0.0),     // coherence: 0.0 => 0.0 * 100.0 = 0.0
            (0.1, 10.0),    // coherence: 0.1 => 0.1 * 100.0 = 10.0
            (0.33, 33.0),   // coherence: 0.33 => 0.33 * 100.0 = 33.0
            (0.678, 67.8),  // coherence: 0.678 => 0.678 * 100.0 = 67.8
            (0.999, 99.9),  // coherence: 0.999 => 0.999 * 100.0 = 99.9
            (1.0, 100.0),   // coherence: 1.0 => 1.0 * 100.0 = 100.0
        ];

        for (coherence, expected) in coherence_test_cases.iter() {
            let charset_match = CharsetMatch::new(
                &b"Test"[..],
                "utf-8",
                0.01,
                false,
                &vec![
