                        language: &Language::Russian,
                        score: *coherence,
                    },
                ],
                None,
            );

            let result = charset_match.coherence_percents();
            assert!((result - *expected).abs() < 0.0001, "Expected {}, got {}", expected, result);
        }
    }
}

