            .expect("Decoding failed");
        let decoded_b = decode(&to_be_decoded, iana_name_b, DecoderTrap::Ignore, false, false)
            .expect("Decoding failed");

        if decoded_a == decoded_b {
            character_match_count += 1;
        }
    }

    character_match_count as f32 / 254.0
