from .constant import FREQUENCIES

class UnicodeRangeLanguagesTest(unittest.TestCase):
    def test_basic_functionality(self):
        """Test that the function returns languages for a given unicode range."""
        # Test with a range that should return languages
        languages = unicode_range_languages("Latin Extended-A")
        self.assertTrue(len(languages) > 0, "Should return at least one language for Latin Extended-A")

        # Test with a range that shouldn't have languages
        languages = unicode_range_languages("Nonexistent Range")
        self.assertEqual(languages, [], "Should return empty list for nonexistent range")

    def test_language_matching(self):
        """Test that languages are correctly matched to unicode ranges."""
        # Get a character from a language and find its range
        sample_languages = list(FREQUENCIES.keys())[:5]  # Take first 5 languages for testing

        for language in sample_languages:
            if not FREQUENCIES[language]:
                continue  # Skip languages with empty character sets

            character = FREQUENCIES[language][0]
            char_range = unicode_range(character)

            if char_range:  # Only test if we get a valid range
                languages = unicode_range_languages(char_range)
                self.assertIn(language, languages, 
                              f"Language {language} should be in result for character {character} with range {char_range}")

    def test_behavior_with_multiple_languages(self):
        """Test that multiple languages using the same unicode range are correctly identified."""
        # Find a unicode range used by multiple languages
        range_to_languages = {}
        for language, characters in FREQUENCIES.items():
            for character in characters:
                char_range = unicode_range(character)
                if char_range:
                    if char_range not in range_to_languages:
                        range_to_languages[char_range] = []
                    if language not in range_to_languages[char_range]:
                        range_to_languages[char_range].append(language)

        # Find a range used by multiple languages
        multi_language_range = None
        for r, langs in range_to_languages.items():
            if len(langs) > 1:
                multi_language_range = r
                break

        if multi_language_range:
            languages = unicode_range_languages(multi_language_range)
            # Check that languages found match our expectations
            for expected_lang in range_to_languages[multi_language_range]:
                self.assertIn(expected_lang, languages, 
                             f"Language {expected_lang} should be detected for range {multi_language_range}")

if __name__ == '__main__':
    unittest.main()

