pub(crate) fn range_scan(decoded_sequence: &str) -> HashSet<String> {
    let mut ranges: HashSet<String> = HashSet::new();

    for character in decoded_sequence.chars() {
        if let Some(character_range) = unicode_range(character) {
            ranges.insert(character_range.to_string());
        }
    }

    // Convert HashSet to Vec and sort for consistent ordering
    let mut result_vec: Vec<String> = ranges.into_iter().collect();
    result_vec.sort();

    // Convert back to HashSet to match the function signature
    let final_set: HashSet<String> = result_vec.into_iter().collect();
    final_set
}

