use crate::consts::TOO_BIG_SEQUENCE;
use std::cmp::Ordering;

#[test]
fn test_comparison_logic() {
    // Test cases for different scenarios in the partial_cmp method

    // Create base CharsetMatch instances for testing
    let match1 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.05,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.8,
            },
        ],
        Some("Test"),
    );

    let match2 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.05,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.8,
            },
        ],
        Some("Test"),
    );

    // Test case 1: Similar chaos (< 0.01 diff), significant coherence diff (> 0.02)
    // Should compare based on coherence, higher coherence should be "less than"
    let mut match1 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.05,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.9,
            },
        ],
        Some("Test"),
    );

    let mut match2 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.055,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.85,
            },
        ],
        Some("Test"),
    );

    assert_eq!(match1.partial_cmp(&match2), Some(Ordering::Less));
    assert_eq!(match2.partial_cmp(&match1), Some(Ordering::Greater));

    // Test case 2a: Similar chaos (< 0.01 diff), similar coherence (≤ 0.02), small payload
    // Should compare based on multi_byte_usage, higher usage should be "less than"
    let mut match1 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.05,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.9,
            },
        ],
        Some("T"),  // Manipulated to change multi_byte_usage
    );

    let mut match2 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.055,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.89,  // Only 0.01 difference
            },
        ],
        Some("Test"),  // Manipulated to change multi_byte_usage
    );

    // match1 should have higher multi_byte_usage due to shorter decoded payload
    assert_eq!(match1.partial_cmp(&match2), Some(Ordering::Less));
    assert_eq!(match2.partial_cmp(&match1), Some(Ordering::Greater));

    // Test case 2b: Similar chaos (< 0.01 diff), similar coherence (≤ 0.02), large payload
    // Should compare based on chaos, lower chaos should be "less than"
    let big_payload = vec![b'a'; TOO_BIG_SEQUENCE];
    let mut match1 = CharsetMatch::new(
        &big_payload,
        "utf-8",
        0.05,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.9,
            },
        ],
        None,  // Let the CharsetMatch decode it
    );

    let mut match2 = CharsetMatch::new(
        &big_payload,
        "utf-8",
        0.055,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.89,
            },
        ],
        None,  // Let the CharsetMatch decode it
    );

    assert_eq!(match1.partial_cmp(&match2), Some(Ordering::Less));
    assert_eq!(match2.partial_cmp(&match1), Some(Ordering::Greater));

    // Test case 3: Different chaos (≥ 0.01 diff)
    // Should compare based on chaos, lower chaos should be "less than"
    let mut match1 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.05,
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.9,
            },
        ],
        Some("Test"),
    );

    let mut match2 = CharsetMatch::new(
        &[b'T', b'e', b's', b't'],
        "utf-8",
        0.07,  // Difference > 0.01
        false,
        &vec![
            CoherenceMatch {
                language: &Language::English,
                score: 0.95,  // Even higher coherence, but chaos difference is significant
            },
        ],
        Some("Test"),
    );

    assert_eq!(match1.partial_cmp(&match2), Some(Ordering::Less));
    assert_eq!(match2.partial_cmp(&match1), Some(Ordering::Greater));
}

