pub(crate) fn coherence_ratio(
    decoded_sequence: String,
    threshold: Option<OrderedFloat<f32>>,
    include_languages: Option<Vec<&'static Language>>,
) -> Result<CoherenceMatches, String> {
    let mut results: Vec<CoherenceMatch> = Vec::new();
    let mut sufficient_match_count: usize = 0;

    // Default threshold to 0.1 if not provided
    let threshold = threshold.map(|t| t.into_inner()).unwrap_or(0.1);

    // Default to empty list if none provided
    let lg_inclusion_list = include_languages.unwrap_or_default();

    // Check for Latin Based equivalent (in Python this is a string check for "Latin Based")
    // In Rust we consider English as the marker for this flag
    let ignore_non_latin = lg_inclusion_list.iter().any(|&lang| matches!(lang, Language::English));

    // Process each layer from unicode splitting
    for layer in alpha_unicode_split(&decoded_sequence) {
        let sequence_frequencies: Counter<char> = layer.chars().collect();
        let most_common: Vec<(char, usize)> = sequence_frequencies.most_common();

        let character_count: usize = most_common.iter().map(|&(_, count)| count).sum();

        // Skip if sequence is too small
        if character_count <= TOO_SMALL_SEQUENCE {
            continue;
        }

        // Create ordered characters string based on frequency
        let popular_character_ordered: String = most_common.iter().map(|&(c, _)| c).collect();

        // Convert characters to vector for alphabet_languages function
        let popular_chars: Vec<char> = popular_character_ordered.chars().collect();

        // In Python, an empty lg_inclusion_list causes alphabet_languages to be used
        // We maintain the same behavior here
        let languages_to_check = if !lg_inclusion_list.is_empty() {
            lg_inclusion_list.clone()
        } else {
            alphabet_languages(&popular_chars, ignore_non_latin)
        };

        // Process each language and check for matches
        for language in languages_to_check {
            let ratio = characters_popularity_compare(language, &popular_character_ordered)?;

            // Skip if below threshold
            if ratio < threshold {
                continue;
            } 
            // Increment sufficient match count if above threshold
            else if ratio >= 0.8 {
                sufficient_match_count += 1;
            }

            // Add to results with rounded score (4 decimal places like Python)
            let rounded_ratio = (ratio * 10000.0).round() / 10000.0;
            results.push(CoherenceMatch {
                language,
                score: rounded_ratio,
            });

            // Break early if we have enough high-quality matches
            if sufficient_match_count >= 3 {
                break;
            }
        }
    }

    // Filter and sort results before returning
    let mut filtered_results = filter_alt_coherence_matches(&results);
    filtered_results.sort_by(|a, b| b.score.partial_cmp(&a.score).unwrap());

    Ok(filtered_results)
}

