pub fn multi_byte_usage(&self) -> f32 {
    // Handle empty payload (avoid division by zero)
    if self.payload.is_empty() {
        return 0.0;
    }

    // For null decoded payload, return 1.0 (all bytes are "wasted")
    // This matches Python behavior where a decoding error would raise an exception
    if self.decoded_payload().is_none() {
        return 1.0;
    }

    // Standard calculation for valid decoded payload - this should match Python's behavior
    // Python: 1.0 - (len(str(self)) / len(self.raw))
    let decoded_len = self.decoded_payload().map_or(0, |s| s.chars().count()) as f32;
    let raw_len = self.payload.len() as f32;

    1.0 - (decoded_len / raw_len)
}

