pub(crate) fn encoding_unicode_range(iana_name: &str) -> Result<Vec<&str>, String> {
    if is_multi_byte_encoding(iana_name) {
        return Err("Function not supported on multi-byte code page".to_string());
    }

    let mut seen_ranges: HashMap<&str, usize> = HashMap::new();
    let mut character_count: usize = 0;

    for i in 0x40..0xFF {
        let chunk = match crate::utils::decode(&[i], iana_name, DecoderTrap::Ignore, false, false) {
            Ok(s) => s,
            Err(_) => continue,
        };

        if !chunk.is_empty() {
            if let Some(character) = chunk.chars().next() {
                if let Some(character_range) = unicode_range(character) {
                    if !is_unicode_range_secondary(character_range) {
                        *seen_ranges.entry(character_range).or_insert(0) += 1;
                        character_count += 1;
                    }
                }
            }
        }
    }

    let mut result: Vec<&str> = seen_ranges
        .iter()
        .filter(|&(_, &count)| (count as f64 / character_count as f64) >= 0.15)
        .map(|(&range, _)| range)
        .collect();

    // Sort the result to match Python's sorted behavior
    result.sort();

    Ok(result)
}
